import { Component, h, Prop, Element, Listen, Event, EventEmitter, State } from '@stencil/core';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { customTwMerge, generateRandId } from '../../utils/utils';
import { getNavItemLinkRel } from '../../utils/nav-item-link';
import { getColorClass, getLabelClass, containerBaseClass } from './wdpr-nav-item-large.utils';
import { NavItemLargeClickDetail } from './wdpr-nav-item-large.model';

@Component({
  tag: 'wdpr-nav-item-large',
  shadow: true,
})
export class WdprNavItemLarge {
  @Element() el: HTMLWdprNavItemLargeElement;
  @State() _internalId: string;
  @Prop() label!: string;
  @Prop({ reflect: true }) disabled?: boolean = false;
  @Prop({ reflect: true }) inverse?: boolean = false;
  @Prop({ reflect: true }) allowBoldText?: boolean = false;
  @Prop({ reflect: true }) selected?: boolean = false;
  @Prop() itemId?: string;
  @Prop({ reflect: true }) href?: string;
  @Prop({ reflect: true }) target?: string;
  @Prop({ reflect: true }) rel?: string;

  @Event() wdprNavItemLargeClick: EventEmitter<NavItemLargeClickDetail>;

  componentWillLoad() {
    this._internalId = this.itemId || `wdpr-nav-item-large-${generateRandId()}`;
  }

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
      
      return;
    }

    if (this._isNavLink) {
      return;
    }

    if (ev.key == KEYBOARD_KEYS.ENTER || ev.key == KEYBOARD_KEYS.SPACE) {
      ev.preventDefault();
      this._itemClick();
    }
  }

  private get _labelClass(): string {
    return getLabelClass(this._colorClass, this.allowBoldText);
  }

  private get _colorClass(): string {
    return getColorClass(this.disabled, this.inverse);
  }

  private get _containerClass(): string {
    return customTwMerge(containerBaseClass, this.inverse ? 'focus-visible:outline-stroke-inverse' : '');
  }

  private get _isNavLink(): boolean {
    return Boolean(this.href?.trim()) && !this.disabled;
  }

  private get _anchorClass(): string {
    return customTwMerge(this._containerClass, 'no-underline');
  }

  private _itemClick() {
    if (this.disabled) return;

    this.selected = !this.selected;
    this.wdprNavItemLargeClick.emit(this._internalId);
  }

  private _onLinkClick = () => {
    if (this.disabled) return;
    this.wdprNavItemLargeClick.emit(this._internalId);
  };

  render() {
    if (this._isNavLink) {
      return (
        <a
          class={this._anchorClass}
          href={this.href!.trim()}
          id={this._internalId}
          aria-current={this.selected ? 'page' : undefined}
          target={this.target}
          rel={getNavItemLinkRel(this.target, this.rel)}
          onClick={this._onLinkClick}
        >
          <span class={this._labelClass}>{this.label}</span>
        </a>
      );
    }

    return (
      <div
        class={this._containerClass}
        tabIndex={this.disabled ? -1 : 0}
        role="button"
        aria-pressed={this.selected ? 'true' : 'false'}
        aria-disabled={this.disabled ? 'true' : 'false'}
        id={this._internalId}
        onClick={this._itemClick.bind(this)}
      >
        <span class={this._labelClass}>{this.label}</span>
      </div>
    );
  }
}
